const payload = $json.body ?? $json;
const risks = Array.isArray(payload.risks) ? payload.risks : [];
const highRiskCount = Number(payload.high_risk_count ?? risks.filter((risk) => risk.severity === '高').length);
const riskCount = Number(payload.risk_count ?? risks.length);
const reviewEmail = String(payload.review_email ?? '').trim();
const riskSummary = risks.map((risk, index) => `${index + 1}. ${risk.risk_type ?? '未知风险'}（${risk.severity ?? '未知'}）：${risk.evidence ?? ''}`).join('\n');
return [{
  json: {
    company_name: payload.company_name ?? '未知企业',
    reporting_year: payload.reporting_year ?? '',
    risk_count: riskCount,
    high_risk_count: highRiskCount,
    should_notify: Boolean(reviewEmail) && highRiskCount > 0,
    review_email: reviewEmail,
    email_subject: payload.email_subject ?? `FinAudit-Graph 审计复核提醒：${payload.company_name ?? '未知企业'}`,
    email_body: payload.email_body ?? [
      'FinAudit-Graph 已完成一份审计分析，请关注以下复核线索。',
      '',
      `被审计单位：${payload.company_name ?? '未知企业'}`,
      `报告年度：${payload.reporting_year ?? ''}`,
      `风险总数：${riskCount}`,
      `高风险数量：${highRiskCount}`,
      '',
      '风险摘要：',
      riskSummary || '- 暂未识别到审计风险。',
      '',
      '请登录系统查看完整审计报告和底稿证据。'
    ].join('\n'),
    received_at: new Date().toISOString()
  }
}];
